foreach($e in $sources.GetEnumerator()){$path=Join-Path $outDir ($e.Key+'.png');if([IO.File]::Exists($path)){throw "Refusing overwrite $path"};$src=[Drawing.Bitmap]::FromFile($e.Value);try{$w=$src.Width;$h=$src.Height;$bg=New-Object 'bool[,]' $w,$h;$q=New-Object 'System.Collections.Generic.Queue[int]';for($x=0;$x -lt $w;$x++){foreach($y in @(0,($h-1))){if(Is-Key $src.GetPixel($x,$y)){$bg[$x,$y]=$true;$q.Enqueue($y*$w+$x)}}};for($y=0;$y -lt $h;$y++){foreach($x in @(0,($w-1))){if(-not $bg[$x,$y] -and (Is-Key $src.GetPixel($x,$y))){$bg[$x,$y]=$true;$q.Enqueue($y*$w+$x)}}};while($q.Count -gt 0){$i=$q.Dequeue();$x=$i%$w;$y=[int][Math]::Floor($i/$w);foreach($n in @(@(($x-1),$y),@(($x+1),$y),@($x,($y-1)),@($x,($y+1)))){$nx=$n[0];$ny=$n[1];if($nx -ge 0 -and $nx -lt $w -and $ny -ge 0 -and $ny -lt $h -and -not $bg[$nx,$ny] -and (Is-Key $src.GetPixel($nx,$ny))){$bg[$nx,$ny]=$true;$q.Enqueue($ny*$w+$nx)}}};$cut=New-Object Drawing.Bitmap($w,$h,[Drawing.Imaging.PixelFormat]::Format32bppArgb);for($y=0;$y -lt $h;$y++){for($x=0;$x -lt $w;$x++){if($bg[$x,$y]){$cut.SetPixel($x,$y,[Drawing.Color]::Transparent)}else{$p=$src.GetPixel($x,$y);$cut.SetPixel($x,$y,[Drawing.Color]::FromArgb(255,$p.R,$p.G,$p.B))}}};$final=New-Object Drawing.Bitmap(512,512,[Drawing.Imaging.PixelFormat]::Format32bppArgb);$gr=[Drawing.Graphics]::FromImage($final);try{$gr.Clear([Drawing.Color]::Transparent);$gr.CompositingMode=[Drawing.Drawing2D.CompositingMode]::SourceCopy;$gr.InterpolationMode=[Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic;$gr.DrawImage($cut,0,0,512,512);for($y=0;$y -lt 512;$y++){for($x=0;$x -lt 512;$x++){$p=$final.GetPixel($x,$y);if($p.A -lt 24){$final.SetPixel($x,$y,[Drawing.Color]::Transparent)}}};$final.Save($path,[Drawing.Imaging.ImageFormat]::Png)}finally{$gr.Dispose();$final.Dispose();$cut.Dispose()}}finally{$src.Dispose()}}
